/**
 * Address: 0x00A354F0 (FUN_00A354F0)
 *
 * What it does:
 * Probes whether one optional registry subkey exists under `rootKey`; empty
 * subkey text is treated as success.
 */
[[maybe_unused]] bool wxRegistrySubKeyExistsRuntime(
  const wchar_t* const subKeyPath,
  const HKEY rootKey,
  HKEY openedKeyHint
)
{
  HKEY openedKey = openedKeyHint;
  if (subKeyPath == nullptr || *subKeyPath == L'\0') {
    return true;
  }

  if (::RegOpenKeyW(rootKey, subKeyPath, &openedKey) != ERROR_SUCCESS) {
    return false;
  }

  (void)::RegCloseKey(openedKey);
  return true;
}

/**
 * Address: 0x0096B2D0 (FUN_0096B2D0)
 *
 * What it does:
 * Resolves the active Win32 window handle and maps it to one wx runtime
 * window object.
 */
[[maybe_unused]] wxWindowMswRuntime* wxGetActiveWindowRuntime()
{
  const HWND activeWindow = ::GetActiveWindow();
  if (activeWindow == nullptr) {
    return nullptr;
  }

  return wxFindWinFromHandle(static_cast<int>(reinterpret_cast<std::intptr_t>(activeWindow)));
}

