[[maybe_unused]] bool wxIsPointerOwnerFlagBit0Clear(
  const PointerOwnerRuntimeFlagQueryView* const holder
) noexcept
{
  const auto* const owner = static_cast<const OwnerFlagLane4CRuntimeView*>(holder->owner);
  if (owner == nullptr) {
    return false;
  }

  return ((~owner->flags4C) & 1u) != 0u;
}

