  /**
   * Address: 0x00A1A720 (FUN_00A1A720)
   *
   * What it does:
   * Returns the current-group entry count, optionally recursing through child
   * groups by temporarily swapping the active-group lane.
   */
  [[nodiscard]] int WxFileConfigGetNumberOfEntriesRuntime(
    WxFileConfigRuntimeView* const ownerConfig,
    const bool recursive
  )
  {
    WxFileConfigGroupRuntimeView* const savedGroup = ownerConfig->currentGroup;
    int totalEntries = static_cast<int>(savedGroup->entryCount);
    if (!recursive) {
      return totalEntries;
    }

    const std::uint32_t childGroupCount = savedGroup->childGroupCount;
    auto* const vtable = static_cast<WxFileConfigTraversalDispatchRuntimeView*>(ownerConfig->vtable);
    for (std::uint32_t childIndex = 0; childIndex < childGroupCount; ++childIndex) {
      ownerConfig->currentGroup = savedGroup->childGroups[childIndex];
      totalEntries += vtable->getNumberOfEntries(ownerConfig, 1);
      ownerConfig->currentGroup = savedGroup;
    }
    return totalEntries;
  }

