  [[nodiscard]] std::int32_t WxCompareWideTextLanesByLengthAndContent(
    const wchar_t* const* const left,
    const wchar_t* const* const right
  ) noexcept
  {
    const wchar_t* const leftText = (left != nullptr && *left != nullptr) ? *left : L"";
    const wchar_t* const rightText = (right != nullptr && *right != nullptr) ? *right : L"";

    if (std::wcslen(leftText) != std::wcslen(rightText)) {
      return 1;
    }
    return std::wcscmp(leftText, rightText) == 0 ? 0 : 1;
  }

