    (void)::LineTo(deviceContext, rcDst.left + 1, rcDst.top + 1);
    (void)::LineTo(deviceContext, rcDst.right - 1, rcDst.top + 1);

    (void)::SelectObject(deviceContext, lightPen);
    (void)::MoveToEx(deviceContext, rcDst.left + 1, rcDst.bottom - 1, nullptr);
    (void)::LineTo(deviceContext, rcDst.right - 1, rcDst.bottom - 1);
    (void)::LineTo(deviceContext, rcDst.right - 1, rcDst.top);
