[[maybe_unused]] std::int32_t WxWordArrayFindExactValueIndexLinearRuntime(
  const WxWordArrayRuntimeView* const array,
  const std::int16_t value,
  const bool searchFromBack
) noexcept
{
  if (searchFromBack) {
    std::int32_t index = static_cast<std::int32_t>(array->size);
    if (index > 0) {
      const std::int16_t* cursor = array->data + index;
      while (true) {
        --cursor;
        --index;
        if (*cursor == value) {
          return index;
        }
        if (index == 0) {
          return -1;
        }
      }
    }
    return -1;
  }

  const std::uint32_t size = array->size;
  std::int32_t index = 0;
  if (size == 0u) {
    return -1;
  }

  for (const std::int16_t* cursor = array->data; *cursor != value; ++cursor) {
    ++index;
    if (static_cast<std::uint32_t>(index) >= size) {
      return -1;
    }
  }
  return index;
}

