[[maybe_unused]] wxNodeBaseRuntime* wxListAppendIntegerKeyedValueRuntime(
  WxListAppendCommonRuntimeView* const list,
  void* const keyPayload,
  void* const value
) noexcept
{
  if (list == nullptr) {
    return nullptr;
  }

  const std::int32_t keyType = list->keyType;
  if (keyType != wxKEY_INTEGER_RUNTIME &&
      (keyType != wxKEY_NONE_RUNTIME || list->itemCount != 0)) {
    return nullptr;
  }

  wxListKeyRuntime key{};
  key.mKeyType = wxKEY_INTEGER_RUNTIME;
  key.mKey.integer = reinterpret_cast<std::uintptr_t>(keyPayload);

  auto* const dispatch = reinterpret_cast<WxListInsertDispatchRuntime*>(list);
  wxNodeBaseRuntime* const node = dispatch->CreateNode(list->last, nullptr, value, &key);
  if (key.mKeyType == wxKEY_STRING_RUNTIME) {
    _free_crt(const_cast<wchar_t*>(key.mKey.string));
  }

  return wxListAppendCommonRuntime(list, node);
}

