[[maybe_unused]] bool wxShellExecuteViaComspecRuntime(
  const wxStringRuntime* const commandText
)
{
  const wchar_t* comspec = _wgetenv(L"COMSPEC");
  if (comspec == nullptr || *comspec == L'\0') {
    comspec = L"\\COMMAND.COM";
  }

  std::wstring shellCommand(comspec);
  const wchar_t* const commandBody =
    (commandText != nullptr && commandText->m_pchData != nullptr) ? commandText->c_str() : wxEmptyString;
  if (commandBody != nullptr && *commandBody != L'\0') {
    shellCommand.append(L" /c ");
    shellCommand.append(commandBody);
  }

  return _wsystem(shellCommand.c_str()) == 0;
}

