/**
 * Address: 0x009727E0 (FUN_009727E0)
 *
 * What it does:
 * Opens one file-path stream when the file exists and probes supported image
 * signatures; otherwise emits the localized "file does not exist" wx error.
 */
[[maybe_unused]] bool wxImageCanReadFilePathRuntime(
  wxStringRuntime* const filePath
)
{
  if (wxFileExists(filePath)) {
    wxFileInputStream inputStream(*filePath);
    return wxInputStreamHasPngSignature(&inputStream) || wxInputStreamHasXpmSignature(&inputStream);
  }

  const wchar_t* messageTemplate = L"Can't check image format of file '%s': file does not exist.";
  if (wxLocale* const locale = wxGetLocale(); locale != nullptr) {
    messageTemplate = locale->GetString(messageTemplate, 0);
  }

  const wchar_t* const missingPath = (filePath != nullptr && filePath->m_pchData != nullptr) ? filePath->c_str() : wxEmptyString;
  wxLogError(messageTemplate, missingPath);
  return false;
}

