wxStringRuntime* wxString::InitWith(
  wxStringRuntime* const outValue,
  const wchar_t* const sourceText,
  const std::int32_t beginOffset,
  const std::int32_t lengthHint
)
{
  if (outValue == nullptr) {
    return nullptr;
  }

  const wchar_t* const source = sourceText != nullptr ? sourceText : wxEmptyString;
  const std::size_t sourceLength = std::wcslen(source);
  std::size_t startOffset = 0u;
  if (beginOffset > 0) {
    startOffset = static_cast<std::size_t>(beginOffset);
    if (startOffset > sourceLength) {
      startOffset = sourceLength;
    }
  }

  const wchar_t* const start = source + startOffset;
  const std::size_t remaining = sourceLength - startOffset;
  std::size_t charCount = remaining;
  if (lengthHint != -101) {
    if (lengthHint <= 0) {
      charCount = 0u;
    } else {
      const std::size_t requested = static_cast<std::size_t>(lengthHint);
      charCount = (requested < remaining) ? requested : remaining;
    }
  }

  (void)wxAssignWideSpanToRuntimeString(outValue, charCount, start);
  return outValue;
}

wxStringRuntime* wxString::append(
  wxStringRuntime* const outValue,
  const std::int32_t lengthHint,
  const wchar_t* const sourceText
)
{
  if (outValue == nullptr || sourceText == nullptr) {
    return outValue;
  }

  std::size_t appendLength = 0u;
  if (lengthHint == -101) {
    appendLength = std::wcslen(sourceText);
  } else if (lengthHint > 0) {
    appendLength = static_cast<std::size_t>(lengthHint);
  }

  if (appendLength == 0u) {
    return outValue;
  }

  std::wstring mergedText = std::wstring(outValue->c_str());
  mergedText.append(sourceText, sourceText + appendLength);
  (void)wxAssignWideSpanToRuntimeString(outValue, mergedText.size(), mergedText.c_str());
  return outValue;
}

