  void WxListSortNodeValueLanesRuntime(
    WxListInsertRuntimeView* const listRuntime,
    const WxQSortCompareFn compareFunction
  ) noexcept
  {
    if (listRuntime == nullptr || compareFunction == nullptr || listRuntime->itemCount <= 1) {
      return;
    }

    std::vector<void*> values{};
    values.reserve(static_cast<std::size_t>(listRuntime->itemCount));
    for (wxNodeBaseRuntime* node = listRuntime->first; node != nullptr; node = node->mNext) {
      values.push_back(node->mValue);
    }

    if (values.size() <= 1u) {
      return;
    }

    std::qsort(values.data(), values.size(), sizeof(void*), compareFunction);

    std::size_t index = 0u;
    for (wxNodeBaseRuntime* node = listRuntime->first; node != nullptr && index < values.size(); node = node->mNext, ++index) {
      node->mValue = values[index];
    }
  }

