  [[maybe_unused]] void wxListAppendCopiedWideValuesRuntime(
    WxListInsertRuntimeView* const destinationList,
    const void* const sourceListRuntime
  )
  {
    if (destinationList == nullptr || sourceListRuntime == nullptr) {
      return;
    }

    const auto* const source = static_cast<const WxListInsertRuntimeView*>(sourceListRuntime);
    for (std::int32_t index = 0; index < source->itemCount; ++index) {
      wxNodeBaseRuntime* const node = WxListNodeAtIndexRuntime(source, index);
      const wchar_t* const nodeText = (node != nullptr && node->mValue != nullptr)
        ? static_cast<const wchar_t*>(node->mValue)
        : L"";
      auto* const textCopy = wx::copystring(nodeText);
      (void)wxListInsertAtIndexOrAppendRuntime(destinationList, destinationList->itemCount, textCopy);
    }
  }

  [[nodiscard]] wxNodeBaseRuntime* WxListInsertValueAtIndexRuntime(
    WxListInsertRuntimeView* const listRuntime,
    const std::int32_t insertionIndex,
    void* const valueRuntime
  )
  {
    if (listRuntime == nullptr || insertionIndex < 0) {
      return nullptr;
    }

    auto* const list = listRuntime;
    if (insertionIndex == list->itemCount) {
      return wxListInsertAtIndexOrAppendRuntime(list, insertionIndex, valueRuntime);
    }

    wxNodeBaseRuntime* const insertionPoint = WxListNodeAtIndexRuntime(list, insertionIndex);
    if (insertionPoint == nullptr) {
      return nullptr;
    }

    return wxListInsertBeforeNodeRuntime(list, insertionPoint, valueRuntime);
  }

