/**
 * Address: 0x00A0FBD0 (FUN_00A0FBD0)
 *
 * What it does:
 * Reads one FTP reply (including multi-line continuation), appends full reply
 * text to runtime buffer lane `+0x70`, and returns the status-code first digit.
 */
[[maybe_unused]] char wxFtpReadReplyAndClassifyRuntime(
  WxFtpSocketIoRuntimeView* const runtime
)
{
  wxStringRuntime statusPrefix{};
  statusPrefix.m_pchData = const_cast<wchar_t*>(wxEmptyString);

  wxString::Empty(&runtime->replyBuffer, 0);

  bool expectingFirstLine = true;
  bool replyComplete = false;
  bool parseBroken = false;

  do {
    if (parseBroken) {
      break;
    }

    wxStringRuntime lineValue{};
    lineValue.m_pchData = const_cast<wchar_t*>(wxEmptyString);

    const auto* const vtable = static_cast<const WxFtpSocketIoVTableRuntimeView*>(runtime->vtable);
    const int readStatus = vtable->readReplyLine(runtime, &lineValue);
    runtime->statusCode = readStatus;
    if (readStatus != 0) {
      ReleaseWxStringSharedPayload(lineValue);
      ReleaseWxStringSharedPayload(statusPrefix);
      return 0;
    }

    if (wxWideStringLengthOrZero(runtime->replyBuffer.m_pchData) != 0) {
      const wchar_t newlineCharacter = L'\n';
      wxString::append(&runtime->replyBuffer, 1, &newlineCharacter);
    }

    const std::int32_t lineLength = wxWideStringLengthOrZero(lineValue.m_pchData);
    wxString::append(&runtime->replyBuffer, lineLength, lineValue.m_pchData);

    if (lineLength < 4) {
      if (expectingFirstLine) {
        parseBroken = true;
      } else {
        wxLogTrace(L"ftp", L"<== %s %s", statusPrefix.m_pchData, lineValue.m_pchData);
      }
      ReleaseWxStringSharedPayload(lineValue);
      continue;
    }

    const wchar_t separator = lineValue.m_pchData[3];
    if (expectingFirstLine) {
      wxStringRuntime prefixCopy{};
      prefixCopy.m_pchData = nullptr;
      wxString::InitWith(&prefixCopy, lineValue.m_pchData, 0, 3);
      (void)wxCopySharedWxStringRuntime(&prefixCopy, &statusPrefix);
      ReleaseWxStringSharedPayload(prefixCopy);

      wxLogTrace(L"ftp", L"<== %s %s", statusPrefix.m_pchData, lineValue.m_pchData + 4);
      if (separator == L' ') {
        replyComplete = true;
      } else if (separator == L'-') {
        expectingFirstLine = false;
      } else {
        parseBroken = true;
      }
    } else {
      if (wxCompareWidePrefixRuntime(lineValue.m_pchData, statusPrefix.m_pchData, 3) != 0) {
        wxLogTrace(L"ftp", L"<== %s %s", statusPrefix.m_pchData, lineValue.m_pchData);
      } else {
        if (separator == L' ') {
          replyComplete = true;
        }
        wxLogTrace(L"ftp", L"<== %s %s", statusPrefix.m_pchData, lineValue.m_pchData + 4);
      }
    }

    ReleaseWxStringSharedPayload(lineValue);
  } while (!replyComplete);

  if (parseBroken) {
    wxLogDebug(L"Broken FTP server: '%s' is not a valid reply.", runtime->replyBuffer.m_pchData);
    runtime->statusCode = 2;
    ReleaseWxStringSharedPayload(statusPrefix);
    return 0;
  }

  (void)EnsureUniqueOwnedWxStringBuffer(&statusPrefix);
  const char statusCodeDigit = static_cast<char>(statusPrefix.m_pchData[0]);
  ReleaseWxStringSharedPayload(statusPrefix);
  return statusCodeDigit;
}

