/**
 * Address: 0x00960390 (FUN_00960390)
 *
 * What it does:
 * Scans backward from `startIndex` (`-101` means logical end) and returns the
 * first index whose UTF-16 code unit is not present in `rejectSet`; returns
 * `-101` when all scanned code units belong to `rejectSet`.
 */
[[maybe_unused]] std::int32_t wxFindLastWideCharNotInSetBeforeIndex(
  const wchar_t** const textStorage,
  const wchar_t* const rejectSet,
  std::int32_t startIndex
) noexcept
{
  if (textStorage == nullptr || *textStorage == nullptr || rejectSet == nullptr) {
    return kWxStringSearchNotFound;
  }

  const wchar_t* const text = *textStorage;
  if (startIndex == kWxStringSearchNotFound) {
    startIndex = WxSharedWideStringLengthFromHeader(text);
  }

  const wchar_t* cursor = text + static_cast<std::ptrdiff_t>(startIndex) - 1;
  if (cursor < text) {
    return kWxStringSearchNotFound;
  }

  while (std::wcschr(rejectSet, *cursor) != nullptr) {
    --cursor;
    if (cursor < text) {
      return kWxStringSearchNotFound;
    }
  }

  return static_cast<std::int32_t>(cursor - text);
}

