/**
 * Address: 0x0097DBC0 (FUN_0097DBC0)
 *
 * What it does:
 * Finds one dword value index in forward or reverse direction and returns
 * `-1` when not found.
 */
[[maybe_unused]] int wxFindDwordValueIndexRuntime(
  const WxDwordArrayRuntimeView* const array,
  const std::int32_t value,
  const bool searchFromBack
) noexcept
{
  if (searchFromBack) {
    std::int32_t index = static_cast<std::int32_t>(array->size) - 1;
    if (index < 0) {
      return -1;
    }

    const std::int32_t* cursor = array->data + index;
    while (*cursor != value) {
      --index;
      --cursor;
      if (index == 0) {
        return -1;
      }
    }
    return index;
  }

  const std::uint32_t count = array->size;
  std::uint32_t index = 0u;
  if (count == 0u) {
    return -1;
  }

  const std::int32_t* cursor = array->data;
  while (*cursor != value) {
    ++index;
    ++cursor;
    if (index >= count) {
      return -1;
    }
  }
  return static_cast<int>(index);
}

