/**
 * Address: 0x009B4770 (FUN_009B4770)
 *
 * What it does:
 * Returns whether one `(lane00,lane04)` pair is inside the closed
 * lexicographic range delimited by `rangeStart` and `rangeEnd`.
 */
[[maybe_unused]] BOOL wxIsDwordPairInClosedLexicographicRangeRuntime(
  const WxDwordPairRuntimeCopyView* const value,
  const WxDwordPairRuntimeCopyView* const rangeStart,
  const WxDwordPairRuntimeCopyView* const rangeEnd
) noexcept
{
  const std::uint32_t valueLane00 = static_cast<std::uint32_t>(value->lane00);
  const std::uint32_t valueLane04 = static_cast<std::uint32_t>(value->lane04);
  const std::uint32_t startLane00 = static_cast<std::uint32_t>(rangeStart->lane00);
  const std::uint32_t startLane04 = static_cast<std::uint32_t>(rangeStart->lane04);
  if (valueLane00 == startLane00 && valueLane04 == startLane04) {
    return TRUE;
  }

  const std::uint32_t endLane00 = static_cast<std::uint32_t>(rangeEnd->lane00);
  const std::uint32_t endLane04 = static_cast<std::uint32_t>(rangeEnd->lane04);
  if (valueLane00 == endLane00 && valueLane04 == endLane04) {
    return TRUE;
  }

  if (
    (valueLane04 < startLane04) ||
    ((valueLane04 <= startLane04) && (valueLane00 <= startLane00)) ||
    ((valueLane04 >= endLane04) && ((valueLane04 > endLane04) || (valueLane00 >= endLane00)))
  ) {
    return FALSE;
  }

  return TRUE;
}

struct WxRectDeltaRuntimeView
{
  std::int32_t x = 0;      // +0x00
  std::int32_t y = 0;      // +0x04
  std::int32_t width = 0;  // +0x08
  std::int32_t height = 0; // +0x0C
};
static_assert(sizeof(WxRectDeltaRuntimeView) == 0x10, "WxRectDeltaRuntimeView size must be 0x10");

/**
 * Address: 0x009BC810 (FUN_009BC810)
 *
 * What it does:
 * Computes one union rectangle from two `{x,y,width,height}` payloads and
 * writes the merged bounds into caller-provided output storage.
 */
[[maybe_unused]] WxRectDeltaRuntimeView* wxComputeRectUnionRuntime(
  const WxRectDeltaRuntimeView* const firstRect,
  WxRectDeltaRuntimeView* const outRect,
  const WxRectDeltaRuntimeView* const secondRect
) noexcept
{
  const std::int32_t left = (firstRect->x < secondRect->x) ? firstRect->x : secondRect->x;
  const std::int32_t top = (firstRect->y < secondRect->y) ? firstRect->y : secondRect->y;

  std::int32_t bottom = secondRect->y + secondRect->height;
  const std::int32_t firstBottom = firstRect->y + firstRect->height;
  if (firstBottom > bottom) {
    bottom = firstBottom;
  }

  std::int32_t right = secondRect->x + secondRect->width;
  const std::int32_t firstRight = firstRect->x + firstRect->width;
  if (firstRight > right) {
    right = firstRight;
  }

  outRect->x = left;
  outRect->y = top;
  outRect->width = right - left;
  outRect->height = bottom - top;
  return outRect;
}

/**
 * Address: 0x009BC880 (FUN_009BC880)
 *
 * What it does:
 * Applies one `(dx, dy)` inset delta to `{x,y,width,height}` and clamps all
 * four lanes to non-negative values.
 */
[[maybe_unused]] WxRectDeltaRuntimeView* wxInsetRectByDeltaClampNonNegativeRuntime(
  WxRectDeltaRuntimeView* const rect,
  const std::int32_t dx,
  const std::int32_t dy
) noexcept
{
  rect->x -= dx;
  const std::int32_t x = rect->x;
  rect->y -= dy;
  const std::int32_t y = rect->y;
  rect->width += (dx * 2);
  const std::int32_t width = rect->width;
  rect->height += (dy * 2);
  const std::int32_t height = rect->height;

  if (x < 0) {
    rect->x = 0;
  }
  if (y < 0) {
    rect->y = 0;
  }
  if (width < 0) {
    rect->width = 0;
  }
  if (height < 0) {
    rect->height = 0;
  }
  return rect;
}

