    const std::uint32_t colorTableBytes = static_cast<std::uint16_t>(ComputeDibColorTableBytes(dibInfo));
    const std::uint32_t headerBytes = *reinterpret_cast<const std::uint32_t*>(reinterpret_cast<const std::uint8_t*>(dibInfo));
