  [[nodiscard]] moho::ManagedWindowSlot* AssignManagedWindowSlotRangeForward(
    moho::ManagedWindowSlot* destinationBegin,
    const moho::ManagedWindowSlot* sourceBegin,
    const moho::ManagedWindowSlot* sourceEnd
  ) noexcept
  {
    moho::ManagedWindowSlot* destination = destinationBegin;
    for (const moho::ManagedWindowSlot* source = sourceBegin; source != sourceEnd; ++source, ++destination) {
      destination->ownerHeadLink = source->ownerHeadLink;
      if (source->ownerHeadLink == nullptr) {
        destination->nextInOwnerChain = nullptr;
      } else {
        destination->nextInOwnerChain = *source->ownerHeadLink;
        *source->ownerHeadLink = destination;
      }
    }
    return destination;
  }

  void UnlinkManagedWindowSlotLane(
    moho::ManagedWindowSlot& slot
  ) noexcept
  {
    if (slot.ownerHeadLink == nullptr) {
      return;
    }

    moho::ManagedWindowSlot** link = slot.ownerHeadLink;
    while (*link != nullptr && *link != &slot) {
      link = &(*link)->nextInOwnerChain;
    }
    if (*link == &slot) {
      *link = slot.nextInOwnerChain;
    }
  }

  [[nodiscard]] moho::ManagedWindowSlot* AssignManagedWindowSlotRangeBackward(
    moho::ManagedWindowSlot* destinationEnd,
    const moho::ManagedWindowSlot* sourceBegin,
    const moho::ManagedWindowSlot* sourceEnd
  ) noexcept
  {
    while (sourceBegin != sourceEnd) {
      --sourceEnd;
      --destinationEnd;

      if (sourceEnd->ownerHeadLink != destinationEnd->ownerHeadLink) {
        if (destinationEnd->ownerHeadLink != nullptr) {
          UnlinkManagedWindowSlotLane(*destinationEnd);
        }

        destinationEnd->ownerHeadLink = sourceEnd->ownerHeadLink;
        if (sourceEnd->ownerHeadLink == nullptr) {
          destinationEnd->nextInOwnerChain = nullptr;
        } else {
          destinationEnd->nextInOwnerChain = *sourceEnd->ownerHeadLink;
          *sourceEnd->ownerHeadLink = destinationEnd;
        }
      }
    }

    return destinationEnd;
  }
