  auto* const destination = static_cast<WxHelpEventRuntimeView*>(destinationRuntime);
  const auto* const source = static_cast<const WxHelpEventRuntimeView*>(sourceRuntime);
  if (destination == nullptr) {
    return nullptr;
  }

  static std::uint8_t sWxHelpEventRuntimeVTableTag = 0;

  if (source != nullptr) {
    new (&destination->baseEvent) wxCommandEventRuntime(source->baseEvent);
    destination->pointX = source->pointX;
    destination->pointY = source->pointY;
    retainRuntimeString(&destination->lane3C, &source->lane3C);
    retainRuntimeString(&destination->lane40, &source->lane40);
  } else {
    new (&destination->baseEvent) wxCommandEventRuntime(0, 0);
    destination->pointX = 0;
    destination->pointY = 0;
    destination->lane3C.m_pchData = const_cast<wchar_t*>(wxEmptyString);
    destination->lane40.m_pchData = const_cast<wchar_t*>(wxEmptyString);
  }

  *reinterpret_cast<void**>(destination) = &sWxHelpEventRuntimeVTableTag;
  return destination;
