[[maybe_unused]] bool wxListKeyMatchesStoredNodeKeyRuntime(
  const wxListKeyRuntime* const keyRuntime,
  const wchar_t* const storedNodeKeyLane
) noexcept
{
  if (keyRuntime->mKeyType == wxKEY_INTEGER_RUNTIME) {
    return keyRuntime->mKey.integer == reinterpret_cast<std::uintptr_t>(storedNodeKeyLane);
  }

  return std::wcscmp(keyRuntime->mKey.string, storedNodeKeyLane) == 0;
}

