[[maybe_unused]] moho::ManagedWindowSlot* AssignManagedWindowSlotFillFromTemplateCore(
  moho::ManagedWindowSlot* destinationBegin,
  const std::uint32_t count,
  const moho::ManagedWindowSlot* const sourceTemplate
) noexcept
{
  moho::ManagedWindowSlot* destination = destinationBegin;
  for (std::uint32_t index = 0; index < count; ++index, ++destination) {
    destination->ownerHeadLink = sourceTemplate->ownerHeadLink;
    if (sourceTemplate->ownerHeadLink == nullptr) {
      destination->nextInOwnerChain = nullptr;
    } else {
      destination->nextInOwnerChain = *sourceTemplate->ownerHeadLink;
      *sourceTemplate->ownerHeadLink = destination;
    }
  }
  return destination;
}

