[[maybe_unused]] moho::ManagedWindowSlot* RebindManagedWindowSlotRangeToOwnerHeadLane(
  moho::ManagedWindowSlot* rangeBegin,
  moho::ManagedWindowSlot** const* const ownerHeadLinkLane,
  moho::ManagedWindowSlot* const rangeEnd
) noexcept
{
  while (rangeBegin != rangeEnd) {
    moho::ManagedWindowSlot& slot = *rangeBegin;
    moho::ManagedWindowSlot** const targetOwnerHeadLink = *ownerHeadLinkLane;

    if (targetOwnerHeadLink != slot.ownerHeadLink) {
      if (slot.ownerHeadLink != nullptr) {
        UnlinkManagedWindowSlotLane(slot);
      }

      slot.ownerHeadLink = targetOwnerHeadLink;
      if (targetOwnerHeadLink == nullptr) {
        slot.nextInOwnerChain = nullptr;
      } else {
        slot.nextInOwnerChain = *targetOwnerHeadLink;
        *targetOwnerHeadLink = &slot;
      }
    }

    ++rangeBegin;
  }

  return rangeBegin;
}

