/**
 * Address: 0x006612A0 (FUN_006612A0)
 *
 * What it does:
 * Projects one world-space point lane to integer screen coordinates using one
 * cached affine runtime projection and anchor-mode vertical adjustment.
 */
[[maybe_unused]] int* wxProjectWorldPointToScreenRuntime(
  int* const outScreenPoint,
  const void* const projectionRuntime,
  const std::int32_t verticalAnchorMode,
  const float worldX,
  const float worldY,
  const float verticalSpan
) noexcept
{
  outScreenPoint[0] = 0;
  outScreenPoint[1] = 0;

  auto adjustedY = worldY;
  if (verticalAnchorMode == 0) {
    adjustedY = worldY + (verticalSpan * 0.5f);
  } else if (verticalAnchorMode == 2) {
    adjustedY = worldY - (verticalSpan * 0.5f);
  }

  const auto* const projection = static_cast<const WxWorldToScreenProjectionRuntimeView*>(projectionRuntime);
  const auto projectedX = static_cast<int>(projection->scaleX * (worldX - projection->originX));
  const auto projectedY = static_cast<int>(
    static_cast<float>(projection->baseY) - (projection->scaleY * (adjustedY - projection->originY))
  );

  outScreenPoint[0] = projectedX;
  outScreenPoint[1] = projectedY;
  return outScreenPoint;
}

