/**
 * Address: 0x0097F8B0 (FUN_0097F8B0)
 *
 * What it does:
 * Converts one wide-text lane through converter virtual slot `+0x04`,
 * allocates one NUL-terminated multi-byte buffer, writes converted bytes into
 * that buffer, and stores it in `outTextStorage`.
 */
[[maybe_unused]] char** wxConvertWideTextToAllocatedMultiByteRuntime(
  void* const converterRuntime,
  char** const outTextStorage,
  const void* const sourceWideText
)
{
  if (sourceWideText == nullptr) {
    *outTextStorage = nullptr;
    _free_crt(nullptr);
    return outTextStorage;
  }

  const auto* const vtable = *reinterpret_cast<WxWideToMultiByteDispatchRuntimeVTable**>(converterRuntime);
  const int requiredBytes = vtable->convertToMultiByte(converterRuntime, nullptr, sourceWideText, 0);
  if (requiredBytes == -1) {
    *outTextStorage = nullptr;
    _free_crt(nullptr);
    return outTextStorage;
  }

  auto* const convertedText = static_cast<char*>(std::malloc(static_cast<std::size_t>(requiredBytes) + 1u));
  convertedText[requiredBytes] = '\0';
  (void)vtable->convertToMultiByte(converterRuntime, convertedText, sourceWideText, requiredBytes + 1);
  *outTextStorage = convertedText;
  _free_crt(nullptr);
  return outTextStorage;
}

