  [[nodiscard]] WxMillisecondPairRuntimeView* wxBuildCurrentMillisecondsPair(
    WxMillisecondPairRuntimeView* const outPair
  )
  {
    if (outPair == nullptr) {
      return nullptr;
    }

    __timeb64 currentTime{};
    _ftime64(&currentTime);
    const std::int64_t milliseconds = static_cast<std::int64_t>(currentTime.time) * 1000ll + currentTime.millitm;
    outPair->low = static_cast<std::int32_t>(milliseconds & 0xFFFFFFFFll);
    outPair->high = static_cast<std::int32_t>((milliseconds >> 32) & 0xFFFFFFFFll);
    return outPair;
  }

