/**
 * Address: 0x009BC760 (FUN_009BC760)
 *
 * What it does:
 * Builds one inclusive `x/y/width/height` rectangle from two point lanes and
 * normalizes negative width/height by shifting origin to the min corner.
 */
[[maybe_unused]] WxRectXywhRuntimeView* wxRectFromPointPairInclusiveNormalizedRuntime(
  WxRectXywhRuntimeView* const outRect,
  const WxPointIntRuntimeView* const firstPoint,
  const WxPointIntRuntimeView* const secondPoint
) noexcept
{
  if (outRect == nullptr || firstPoint == nullptr || secondPoint == nullptr) {
    return outRect;
  }

  outRect->x = firstPoint->x;
  outRect->y = firstPoint->y;
  outRect->width = secondPoint->x - firstPoint->x + 1;
  outRect->height = secondPoint->y - firstPoint->y + 1;

  if (outRect->width < 0) {
    outRect->x += outRect->width;
    outRect->width = -outRect->width;
  }

  if (outRect->height < 0) {
    outRect->y += outRect->height;
    outRect->height = -outRect->height;
  }

  return outRect;
}

/**
 * Address: 0x009BC920 (FUN_009BC920)
 *
 * What it does:
 * Clamps one rectangle lane in-place to the overlap against `clipRect`; when
 * overlap is empty, clears both width/height to zero.
 */
[[maybe_unused]] WxRectXywhRuntimeView* wxRectIntersectInPlaceInclusiveRuntime(
  WxRectXywhRuntimeView* const rect,
  const WxRectXywhRuntimeView* const clipRect
) noexcept
{
  if (rect == nullptr || clipRect == nullptr) {
    return rect;
  }

  std::int32_t maxX = rect->x + rect->width - 1;
  std::int32_t maxY = rect->y + rect->height - 1;

  if (rect->x < clipRect->x) {
    rect->x = clipRect->x;
  }
  if (rect->y < clipRect->y) {
    rect->y = clipRect->y;
  }

  const std::int32_t clipMaxX = clipRect->x + clipRect->width - 1;
  const std::int32_t clipMaxY = clipRect->y + clipRect->height - 1;
  if (maxX > clipMaxX) {
    maxX = clipMaxX;
  }
  if (maxY > clipMaxY) {
    maxY = clipMaxY;
  }

  rect->width = maxX - rect->x + 1;
  rect->height = maxY - rect->y + 1;
  if (rect->width <= 0 || rect->height <= 0) {
    rect->width = 0;
    rect->height = 0;
  }

  return rect;
}

