  [[nodiscard]] wxNodeBaseRuntime* WxListAppendRuntime(
    WxListInsertRuntimeView* const list,
    void* const value
  )
  {
    if (list == nullptr || list->mutationLock != 0) {
      return nullptr;
    }

    auto* const dispatch = reinterpret_cast<WxListInsertDispatchRuntime*>(list);
    wxNodeBaseRuntime* const appendedNode =
      dispatch->CreateNode(list->last, nullptr, value, &kWxDefaultListKeyRuntime);
    if (appendedNode == nullptr) {
      return nullptr;
    }

    if (list->first == nullptr) {
      list->first = appendedNode;
    }
    list->last = appendedNode;
    ++list->itemCount;
    return appendedNode;
  }

