  /**
   * Address: 0x0097D7C0 (FUN_0097D7C0)
   *
   * What it does:
   * Reads one palette entry RGB triple from indexed native palette storage.
   */
  [[maybe_unused]] bool wxPaletteGetEntryRgbRuntime(
    const void* const paletteRuntime,
    const std::uint32_t entryIndex,
    std::uint8_t* const outRed,
    std::uint8_t* const outGreen,
    std::uint8_t* const outBlue
  ) noexcept
  {
    if (entryIndex > 0xFFu) {
      return false;
    }

    const auto* const paletteObject = static_cast<const WxObjectRuntimeView*>(paletteRuntime);
    auto* const refData = (paletteObject != nullptr)
      ? static_cast<WxPaletteRefDataDestroyRuntimeView*>(paletteObject->refData)
      : nullptr;
    if (refData == nullptr || refData->paletteHandle == nullptr) {
      return false;
    }

    PALETTEENTRY entry{};
    if (::GetPaletteEntries(refData->paletteHandle, entryIndex, 1u, &entry) == 0u) {
      return false;
    }

    if (outRed != nullptr) {
      *outRed = entry.peRed;
    }
    if (outGreen != nullptr) {
      *outGreen = entry.peGreen;
    }
    if (outBlue != nullptr) {
      *outBlue = entry.peBlue;
    }
    return true;
  }

