  [[nodiscard]] std::uint8_t* wxInputStreamReservePushbackPrefixGap(
    WxInputStreamPushbackRuntimeView* const runtime,
    const std::uint32_t prefixBytes
  ) noexcept
  {
    if (runtime == nullptr) {
      return nullptr;
    }

    const std::uint32_t unreadBytes = runtime->writeOffset - runtime->readOffset;
    auto* const replacement =
      static_cast<std::uint8_t*>(std::malloc(static_cast<std::size_t>(unreadBytes + prefixBytes)));
    if (replacement != nullptr) {
      if (runtime->buffer != nullptr) {
        std::memmove(
          replacement + prefixBytes,
          runtime->buffer + runtime->readOffset,
          unreadBytes
        );
        _free_crt(runtime->buffer);
      }

      runtime->buffer = replacement;
      runtime->writeOffset = unreadBytes + prefixBytes;
      runtime->readOffset = 0u;
    }

    return replacement;
  }

