/**
 * Address: 0x009DD080 (FUN_009DD080)
 *
 * What it does:
 * Prepends one byte span into a stream pushback lane when stream status is
 * below terminal state `2`.
 */
[[maybe_unused]] std::size_t wxInputStreamPushbackWriteRuntime(
  void* const inputStreamRuntime,
  const void* const sourceBytes,
  const std::size_t byteCount
) noexcept
{
  auto* const runtime = static_cast<WxInputStreamPushbackRuntimeView*>(inputStreamRuntime);
  if (runtime == nullptr || sourceBytes == nullptr) {
    return 0u;
  }

  const std::uint32_t streamStatus = runtime->streamStatus;
  if (streamStatus != 0u && streamStatus != 1u) {
    return 0u;
  }

  const std::uint32_t copyBytes = static_cast<std::uint32_t>(byteCount);
  std::uint8_t* const destination = wxInputStreamReservePushbackPrefixGap(runtime, copyBytes);
  if (destination == nullptr) {
    return 0u;
  }

  if (streamStatus == 1u) {
    runtime->streamStatus = 0u;
  }

  std::memcpy(destination, sourceBytes, copyBytes);
  return copyBytes;
}

