/**
 * Address: 0x00A13260 (FUN_00A13260)
 *
 * What it does:
 * Grows one staged input-byte lane in 4 KB chunks, reads from the source
 * stream, and advances staged-byte count by the stream's last-read lane.
 */
[[maybe_unused]] void wxAccumulateInputStreamChunkRuntime(
  WxAccumulatedInputStreamReadBufferRuntimeView* const accumulator
) noexcept
{
  if (accumulator == nullptr || accumulator->sourceStream == nullptr || !accumulator->sourceStream->CanReadChunk()) {
    return;
  }

  const std::uint32_t newBufferSize = accumulator->stagedByteCount + 0x1000u;
  void* const replacement = std::realloc(
    accumulator->stagedBytes,
    static_cast<std::size_t>(newBufferSize)
  );
  if (replacement == nullptr) {
    accumulator->sourceStream = nullptr;
    return;
  }

  auto* const replacementBytes = static_cast<std::uint8_t*>(replacement);
  accumulator->stagedBytes = replacementBytes;
  accumulator->sourceStream->ReadChunk(
    replacementBytes + accumulator->stagedByteCount,
    0x1000u
  );
  accumulator->stagedByteCount += accumulator->sourceStream->GetLastReadByteCount();
}

/**
 * Address: 0x00A132C0 (FUN_00A132C0)
 *
 * What it does:
 * Pushes one staged byte span back into the source stream pushback lane and
 * releases the temporary stage buffer.
 */
[[maybe_unused]] void wxFlushAccumulatedInputStreamChunkRuntime(
  WxAccumulatedInputStreamReadBufferRuntimeView* const accumulator
) noexcept
{
  if (accumulator == nullptr || accumulator->stagedBytes == nullptr) {
    return;
  }

  (void)wxInputStreamPushbackWriteRuntime(
    accumulator->sourceStream,
    accumulator->stagedBytes,
    accumulator->stagedByteCount
  );
  _free_crt(accumulator->stagedBytes);
}

