/**
 * Address: 0x00A2D120 (FUN_00A2D120)
 *
 * What it does:
 * Emits one double-NUL-terminated wide-string block by concatenating all
 * shared-string lanes from a source entry-array runtime into output payload.
 */
[[maybe_unused]] bool wxBuildWideMultiStringFromSharedEntryArrayRuntime(
  const WxSharedWideEntryArrayRuntimeView* const sourceRuntime,
  void* const outputRuntime
)
{
  auto* const output = static_cast<WxWideMultiStringOutputRuntimeView*>(outputRuntime);
  if (output == nullptr || sourceRuntime == nullptr || sourceRuntime->entryCount == 0u) {
    return false;
  }

  output->payloadOffset = 0x14;
  output->lane0C = 0;
  output->lane10 = 1;

  wchar_t* cursor = output->payload;
  for (std::uint32_t entryIndex = 0; entryIndex < sourceRuntime->entryCount; ++entryIndex) {
    const wchar_t* const entryText = sourceRuntime->entries[entryIndex];
    if (entryText == nullptr) {
      *cursor++ = L'\0';
      continue;
    }

    const auto* const sharedPrefixWords =
      reinterpret_cast<const std::int32_t*>(entryText) - 2;
    const std::size_t copySpan = static_cast<std::size_t>(sharedPrefixWords[0]);
    std::memcpy(cursor, entryText, copySpan);

    // Binary path advances by the shared-length lane in wchar_t units.
    cursor += copySpan;
    *cursor++ = L'\0';
  }

  *cursor = L'\0';
  return true;
}

/**
 * Address: 0x00A2D1D0 (FUN_00A2D1D0)
 *
 * What it does:
 * Maps wx socket event-condition flags to the matching Win32 socket notify
 * mask bits.
 */
[[maybe_unused]] std::int32_t wxSocketMapConditionToNotifyMask(
  const std::int32_t conditionFlag
) noexcept
{
  switch (conditionFlag) {
  case 1:
    return 2;
  case 4:
    return 16;
  case 8:
    return 256;
  default:
    return 0;
  }
}

