/**
 * Address: 0x00A2D230 (FUN_00A2D230)
 *
 * What it does:
 * Initializes one `BITMAPINFO` header for the runtime bitmap lane and returns
 * the total byte span (`header+palette+pixel data`) after one/two `GetDIBits`
 * calls, or `0` when extraction fails.
 */
[[maybe_unused]] DWORD wxBuildDibFromBitmapOwnerRuntime(
  LPBITMAPINFO dibInfo,
  const WxBitmapOwnerRuntimeView* const bitmapOwnerRuntime
) noexcept
{
  HBITMAP bitmapHandle = nullptr;
  if (bitmapOwnerRuntime != nullptr && bitmapOwnerRuntime->bitmapCarrier != nullptr) {
    bitmapHandle = bitmapOwnerRuntime->bitmapCarrier->bitmapHandle;
  }

  BITMAP bitmapInfo{};
  if (::GetObjectW(bitmapHandle, sizeof(bitmapInfo), &bitmapInfo) == 0) {
    return 0u;
  }

  BITMAPINFO localDibInfo{};
  LPBITMAPINFO activeDibInfo = (dibInfo != nullptr) ? dibInfo : &localDibInfo;
  const WORD bitCount = static_cast<WORD>(bitmapInfo.bmPlanes * bitmapInfo.bmBitsPixel);
  const std::uint16_t colorEntryCount =
    static_cast<std::uint16_t>(wxSocketMapConditionToNotifyMask(static_cast<std::int32_t>(bitCount)));

  activeDibInfo->bmiHeader.biSize = sizeof(BITMAPINFOHEADER);
  activeDibInfo->bmiHeader.biWidth = bitmapInfo.bmWidth;
  activeDibInfo->bmiHeader.biHeight = bitmapInfo.bmHeight;
  activeDibInfo->bmiHeader.biPlanes = 1u;
  activeDibInfo->bmiHeader.biBitCount = bitCount;
  activeDibInfo->bmiHeader.biCompression = BI_RGB;
  activeDibInfo->bmiHeader.biSizeImage = 0u;
  activeDibInfo->bmiHeader.biXPelsPerMeter = 0;
  activeDibInfo->bmiHeader.biYPelsPerMeter = 0;
  activeDibInfo->bmiHeader.biClrUsed = 0u;
  activeDibInfo->bmiHeader.biClrImportant = 0u;

  const std::uint32_t paletteAndHeaderBytes =
    static_cast<std::uint32_t>(sizeof(BITMAPINFOHEADER) + 4u * colorEntryCount);

  const HDC screenDc = ::GetDC(nullptr);
  const bool readHeaderSucceeded =
    (::GetDIBits(screenDc, bitmapHandle, 0u, static_cast<UINT>(activeDibInfo->bmiHeader.biHeight), nullptr, activeDibInfo, 0u) != 0);
  const bool readPixelsSucceeded =
    (dibInfo == nullptr)
    || (::GetDIBits(
      screenDc,
      bitmapHandle,
      0u,
      static_cast<UINT>(activeDibInfo->bmiHeader.biHeight),
      reinterpret_cast<std::uint8_t*>(activeDibInfo) + paletteAndHeaderBytes,
      activeDibInfo,
      0u
    ) != 0);
  (void)::ReleaseDC(nullptr, screenDc);

  if (!readHeaderSucceeded || !readPixelsSucceeded) {
    return 0u;
  }

  return paletteAndHeaderBytes + activeDibInfo->bmiHeader.biSizeImage;
}

