  [[maybe_unused]] int wxComparePointerPairKeysRuntime(
    const std::uint32_t** const leftPairLane,
    const std::uint32_t** const rightPairLane
  ) noexcept
  {
    const std::uint32_t* const left = *leftPairLane;
    const std::uint32_t* const right = *rightPairLane;
    const std::uint32_t leftValue = left[0];
    const std::uint32_t leftPriority = left[1];
    const std::uint32_t rightValue = right[0];
    const std::uint32_t rightPriority = right[1];

    if (leftValue == rightValue && leftPriority == rightPriority) {
      return 0;
    }

    if (leftPriority > rightPriority || (leftPriority >= rightPriority && leftValue >= rightValue)) {
      return 1;
    }

    return -1;
  }

