  [[nodiscard]] int wxArrayStringFindExactForward(
    const wchar_t* const* const entries,
    const std::uint32_t entryCount,
    const wchar_t* const needle
  ) noexcept
  {
    if (entries == nullptr || needle == nullptr) {
      return -1;
    }

    for (std::uint32_t index = 0u; index < entryCount; ++index) {
      const wchar_t* const entryText = entries[index];
      if (entryText == needle || (entryText != nullptr && std::wcscmp(entryText, needle) == 0)) {
        return static_cast<int>(index);
      }
    }
    return -1;
  }

