  [[maybe_unused]] WxTreeListNodeTraversalRuntimeView** wxResolveNextTreeTraversalNodeRuntime(
    WxTreeListMainWindowTraversalRuntimeView* const ownerRuntime,
    WxTreeListNodeTraversalRuntimeView** const outNodeLane,
    WxTreeListNodeTraversalRuntimeView** const sourceNodeLane
  ) noexcept
  {
    (void)ownerRuntime;

    if (outNodeLane == nullptr) {
      return nullptr;
    }

    auto* currentNode = (sourceNodeLane != nullptr) ? *sourceNodeLane : nullptr;
    if (currentNode == nullptr) {
      *outNodeLane = nullptr;
      return outNodeLane;
    }

    if (currentNode->childNodeArray.entryCount > 0u) {
      *outNodeLane = wxGetNodePointerArrayEntryRuntime(currentNode->childNodeArray, 0u);
      return outNodeLane;
    }

    WxTreeListNodeTraversalRuntimeView* nextNode = nullptr;
    while (currentNode != nullptr && nextNode == nullptr) {
      nextNode = wxGetNextSiblingNodeRuntime(currentNode);
      currentNode = currentNode->parentNode;
    }

    *outNodeLane = nextNode;
    return outNodeLane;
  }

