      static_cast<const WxTreeListEventSourceRuntimeView*>(ownerRuntime->eventSourceRuntime);
    const auto* const viewportMetrics = eventSource->viewportMetrics;
    return (viewportMetrics != nullptr) ? (viewportMetrics->maximumHorizontalExtent + 2) : 2;
