  /**
   * Address: 0x00985700 (FUN_00985700)
   *
   * What it does:
   * Recomputes tree content extents and updates projector scrollbar geometry
   * and origin lanes.
   */
  [[maybe_unused]] int wxRecomputeTreeListProjectorScrollbarsRuntime(
    WxTreeListMainWindowTraversalRuntimeView* const ownerRuntime
  ) noexcept
  {
    if (
      ownerRuntime == nullptr ||
      ownerRuntime->projector.vtable == nullptr ||
      ownerRuntime->projector.vtable->setScrollbars == nullptr
    ) {
      return 0;
    }

    if (ownerRuntime->rootNode == nullptr) {
      return ownerRuntime->projector.vtable->setScrollbars(
        &ownerRuntime->projector,
        0,
        0,
        0,
        0,
        0,
        0,
        0
      );
    }

    int ignoredMaxContentX = 0;
    int maxContentY = 0;
    (void)wxAccumulateTreeNodeSubtreeExtentsRuntime(
      ownerRuntime->rootNode,
      &ignoredMaxContentX,
      &maxContentY,
      ownerRuntime
    );
    maxContentY += 12;

    int horizontalScrollPosition = 0;
    int verticalScrollPosition = 0;
    if (ownerRuntime->vtable != nullptr && ownerRuntime->vtable->queryScrollPosition != nullptr) {
      horizontalScrollPosition = ownerRuntime->vtable->queryScrollPosition(ownerRuntime, 4);
      verticalScrollPosition = ownerRuntime->vtable->queryScrollPosition(ownerRuntime, 8);
    }

    int viewStartX = 0;
    int ignoredViewStartY = 0;
    if (ownerRuntime->vtable != nullptr && ownerRuntime->vtable->queryViewportBounds != nullptr) {
      ownerRuntime->vtable->queryViewportBounds(ownerRuntime, &viewStartX, &ignoredViewStartY);
    }

    const int maxHorizontalExtent = wxReadTreeListMaximumHorizontalExtentPlusTwoRuntime(ownerRuntime);
    if (maxHorizontalExtent < viewStartX) {
      horizontalScrollPosition = 0;
    }

    return ownerRuntime->projector.vtable->setScrollbars(
      &ownerRuntime->projector,
      10,
      10,
      maxHorizontalExtent / 10,
      maxContentY / 10,
      horizontalScrollPosition,
      verticalScrollPosition,
      0
    );
  }

