  [[nodiscard]] constexpr std::uint8_t wxReadByteFromDwordLane(
    const std::uint32_t laneValue,
    const std::uint32_t byteIndex
  ) noexcept
  {
    return static_cast<std::uint8_t>((laneValue >> (byteIndex * 8u)) & 0xFFu);
  }

  [[nodiscard]] constexpr std::uint32_t wxWriteByteIntoDwordLane(
    const std::uint32_t laneValue,
    const std::uint32_t byteIndex,
    const std::uint8_t byteValue
  ) noexcept
  {
    const std::uint32_t shift = byteIndex * 8u;
    const std::uint32_t clearMask = ~(0xFFu << shift);
    return (laneValue & clearMask) | (static_cast<std::uint32_t>(byteValue) << shift);
  }

