  [[maybe_unused]] void wxNotebookApplySelectionTransitionRuntime(
    WxNotebookStateLanesRuntimeView* const notebookRuntime,
    WxNotebookSelectionEventRuntimeView* const eventRuntime
  ) noexcept
  {
    if (eventRuntime->notebookOwner == notebookRuntime) {
      const int previousPageIndex = eventRuntime->previousPageIndex;
      if (previousPageIndex != -1) {
        void* const previousPage = notebookRuntime->pages[previousPageIndex];
        auto* const previousPageVtable = *reinterpret_cast<WxNotebookPageDispatchVTableRuntimeView**>(previousPage);
        previousPageVtable->setNotebookActiveState(previousPage, 0);
      }

      const int selectedPageIndex = eventRuntime->selectedPageIndex;
      if (selectedPageIndex != -1) {
        void* const selectedPage = notebookRuntime->pages[selectedPageIndex];
        auto* const selectedPageVtable = *reinterpret_cast<WxNotebookPageDispatchVTableRuntimeView**>(selectedPage);
        selectedPageVtable->setNotebookActiveState(selectedPage, 1);
        selectedPageVtable->refreshAfterNotebookActivation(selectedPage);
      }

      notebookRuntime->activePageIndex = selectedPageIndex;
    }

    eventRuntime->handledFlag = 1;
  }

